            const _rl_end = std.mem.indexOf(u8, _head, "\r\n") orelse _hl;
            var _rp = std.mem.splitScalar(u8, _head[0.._rl_end], ' ');
            const _method = _rp.next() orelse "GET";
            const _raw_path = _rp.next() orelse "/";
