                    const _rn = std.posix.recv(ctx.conn.stream.handle, _bb[_bi..], 0) catch break;
                    if (_rn == 0) break;
                    _bi += _rn;
                }
                _body = _bb[0.._bi];
                _ = &_peeked;
            }
            const _req = HttpRequest{ .method = _method, .path = _path, .content = _body };
            const _resp = ctx.handler_fn(_req);
