        }
    };
    const _alloc = std.heap.page_allocator;
    var _srv = std.net.Address.initIp4(.{ 0, 0, 0, 0 }, port).listen(.{ .reuse_address = false }) catch |e| {
        std.debug.print("Http.serve: cannot bind port {d}: {s}\n", .{ port, @errorName(e) });
        return;
    };
