    fn eat(c: *_RC) ?u8 { if (c.pos < c.pat.len) { defer c.pos += 1; return c.pat[c.pos]; } return null; }
    fn expect(c: *_RC, ch: u8) bool { if (c.peek() == ch) { c.pos += 1; return true; } return false; }
    fn parseClass(c: *_RC) error{OutOfMemory}![32]u8 {
        var bits = [_]u8{0} ** 32;
