    while (pos < input.len and cur.items.len > 0) : (pos += 1) {
        const ch = input[pos]; nxt.clearRetainingCapacity(); @memset(vis, false);
        for (cur.items) |t| {
            const nd = &re.nodes[t.state];
            const ok = switch (nd.kind) {
